SELECT DISTINCT apparel_type
FROM apparel_size_guides
WHERE is_active = 1;

SELECT COUNT(size_guide_id) AS active_size_guide_count
FROM apparel_size_guides
WHERE brand_id = 1 AND is_active = 1;

SELECT MAX(size_code) AS largest_size
FROM apparel_size_guides
WHERE size_category = 'Women''s' AND apparel_type = 'Tops' AND is_active = 1;

SELECT measurement_type
FROM apparel_size_guide_details
WHERE brand_id = 1;

SELECT style_name, category
FROM styles
ORDER BY style_name;
